1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survivesOrIsBorn = (liveNeighbors: number, wasAlive: boolean): boolean =>
15	  liveNeighbors === 3 || (liveNeighbors === 2 && wasAlive);
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const liveKeys = new Set(cells.map(cellKey));
19	  const wasAlive = (cell: Cell): boolean => liveKeys.has(cellKey(cell));
20	
21	  const candidates = new Map<string, Cell>();
22	  for (const cell of cells) {
23	    for (const candidate of [cell, ...neighborsOf(cell)]) {
24	      candidates.set(cellKey(candidate), candidate);
25	    }
26	  }
27	
28	  return [...candidates.values()].filter((cell) =>
29	    survivesOrIsBorn(neighborsOf(cell).filter(wasAlive).length, wasAlive(cell)),
30	  );
31	}
