export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const liveCell of cells) {
    for (const neighbor of neighborsOf(liveCell)) {
      const key = cellKey(neighbor);
      const entry = neighborCounts.get(key) ?? { cell: neighbor, count: 0 };
      entry.count += 1;
      neighborCounts.set(key, entry);
    }
  }

  return [...neighborCounts.values()]
    .filter(({ cell, count }) => survivesOrIsBorn(count, liveKeys.has(cellKey(cell))))
    .map(({ cell }) => cell);
}

